BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "AlbumPerson" (
	"AlbumId"	TEXT NOT NULL,
	"UserId"	TEXT NOT NULL,
	"AddedAt"	TEXT NOT NULL,
	CONSTRAINT "PK_AlbumPerson" PRIMARY KEY("AlbumId","UserId"),
	CONSTRAINT "FK_AlbumPerson_Albums_AlbumId" FOREIGN KEY("AlbumId") REFERENCES "Albums"("Id") ON DELETE CASCADE,
	CONSTRAINT "FK_AlbumPerson_Users_UserId" FOREIGN KEY("UserId") REFERENCES "Users"("Id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "Albums" (
	"Id"	TEXT NOT NULL,
	"GroupId"	TEXT NOT NULL,
	"Title"	TEXT NOT NULL,
	"Description"	TEXT,
	"DateStart"	TEXT NOT NULL,
	"DateEnd"	TEXT,
	"CreateAt"	TEXT NOT NULL,
	"CreatedByUserId"	TEXT NOT NULL,
	CONSTRAINT "PK_Albums" PRIMARY KEY("Id"),
	CONSTRAINT "FK_Albums_Group_GroupId" FOREIGN KEY("GroupId") REFERENCES "Group"("Id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "Group" (
	"Id"	TEXT NOT NULL,
	"Name"	TEXT NOT NULL,
	"InviteCode"	TEXT NOT NULL,
	"CreatedAt"	TEXT NOT NULL,
	"CreatedByUserId"	TEXT NOT NULL,
	CONSTRAINT "PK_Group" PRIMARY KEY("Id")
);
CREATE TABLE IF NOT EXISTS "GroupMember" (
	"GroupId"	TEXT NOT NULL,
	"UserId"	TEXT NOT NULL,
	"JoinedAt"	TEXT NOT NULL,
	"Role"	INTEGER NOT NULL,
	CONSTRAINT "PK_GroupMember" PRIMARY KEY("GroupId","UserId"),
	CONSTRAINT "FK_GroupMember_Group_GroupId" FOREIGN KEY("GroupId") REFERENCES "Group"("Id") ON DELETE CASCADE,
	CONSTRAINT "FK_GroupMember_Users_UserId" FOREIGN KEY("UserId") REFERENCES "Users"("Id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "Memory" (
	"Id"	TEXT NOT NULL,
	"AlbumId"	TEXT,
	"CreatedAt"	TEXT NOT NULL,
	"CreatedByUserId"	TEXT NOT NULL,
	"GroupId"	TEXT NOT NULL,
	"HappenedAt"	TEXT NOT NULL,
	"MediaUrl"	TEXT,
	"QuoteBy"	TEXT,
	"QuoteText"	TEXT,
	"ThumbUrl"	TEXT,
	"Title"	TEXT,
	"Type"	INTEGER NOT NULL,
	CONSTRAINT "PK_Memory" PRIMARY KEY("Id"),
	CONSTRAINT "FK_Memory_Albums_AlbumId" FOREIGN KEY("AlbumId") REFERENCES "Albums"("Id"),
	CONSTRAINT "FK_Memory_Group_GroupId" FOREIGN KEY("GroupId") REFERENCES "Group"("Id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "MemoryTag" (
	"MemoryId"	TEXT NOT NULL,
	"Value"	TEXT NOT NULL,
	CONSTRAINT "PK_MemoryTag" PRIMARY KEY("MemoryId","Value"),
	CONSTRAINT "FK_MemoryTag_Memory_MemoryId" FOREIGN KEY("MemoryId") REFERENCES "Memory"("Id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "Users" (
	"Id"	TEXT NOT NULL,
	"Email"	TEXT NOT NULL,
	"PasswordHash"	TEXT NOT NULL,
	"CreatedAtUtc"	TEXT NOT NULL,
	"Bio"	TEXT,
	"BirthDate"	TEXT,
	"DiscordTag"	TEXT,
	"DisplayName"	TEXT NOT NULL DEFAULT '',
	"InstagramUrl"	TEXT,
	"PhoneNumber"	TEXT,
	"ProfileImageUrl"	TEXT,
	"Status"	TEXT,
	"TikTokUrl"	TEXT,
	"WebsiteUrl"	TEXT,
	"YouTubeUrl"	TEXT,
	"TwoFactorEnabled"	INTEGER NOT NULL DEFAULT 0,
	"TwoFactorSecret"	TEXT,
	CONSTRAINT "PK_Users" PRIMARY KEY("Id")
);
CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
	"MigrationId"	TEXT NOT NULL,
	"ProductVersion"	TEXT NOT NULL,
	CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY("MigrationId")
);
